<?php
namespace App\Http\Controllers\Api;
use App\Domain\Accounting\Actions\PostJournal;use App\Domain\Accounting\Actions\ReverseJournal;use App\Http\Controllers\Controller;use App\Models\JournalEntry;use Illuminate\Http\JsonResponse;use Illuminate\Http\Request;
class JournalController extends Controller{public function index(Request $request):JsonResponse{return response()->json(JournalEntry::query()->with('lines.account')->when($request->date('from'),fn($q,$v)=>$q->whereDate('entry_date','>=',$v))->when($request->date('to'),fn($q,$v)=>$q->whereDate('entry_date','<=',$v))->latest('entry_date')->paginate());}public function show(JournalEntry $journal):JsonResponse{return response()->json($journal->load(['lines.account','period']));}public function store(Request $request,PostJournal $action):JsonResponse{$d=$request->validate(['reference'=>['nullable','string','max:100'],'entry_date'=>['required','date'],'description'=>['required','string','max:2000'],'currency'=>['sometimes','string','size:3'],'metadata'=>['nullable','array'],'lines'=>['required','array','min:2'],'lines.*.ledger_account_id'=>['required','ulid'],'lines.*.member_id'=>['nullable','ulid'],'lines.*.loan_id'=>['nullable','ulid'],'lines.*.branch_id'=>['nullable','ulid'],'lines.*.debit_minor'=>['required','integer','min:0'],'lines.*.credit_minor'=>['required','integer','min:0'],'lines.*.memo'=>['nullable','string','max:255'],'lines.*.dimensions'=>['nullable','array']]);return response()->json($action->execute($d),201);}public function reverse(Request $request,JournalEntry $journal,ReverseJournal $action):JsonResponse{$d=$request->validate(['reason'=>['required','string','max:2000'],'entry_date'=>['required','date']]);return response()->json($action->execute($journal,$d['reason'],$d['entry_date']),201);}}
